it("should preserve a 2x2 block (still life - each cell has 3 neighbors)", () => {
  const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
  expect(new Set(result.map((c) => (c as number[]).join(",")))).toEqual(
    new Set(["0,0", "1,0", "0,1", "1,1"]),
  );
});
